import { useMemo } from 'react';

import type { TruncationMode } from '../../../../../../../typography/text-ellipsis/TextEllipsis.js';
import {
  GAP_BETWEEN_COLUMNS,
  SPACE_CHARACTER_WIDTH,
} from '../../../constants.js';
import { calculateTotalWidth400 } from '../../../utils/width-calculation.js';
import { buildRelativeValueText } from '../utils/build-relative-value-text.js';
import { getDisplayText } from '../utils/get-display-text.js';

export const useValueContainerDisplayText = (
  value: string,
  valueUnit: string | undefined,
  relativeValue: string | number | undefined,
  relativeValueUnit: string | undefined,
  availableContainerWidth: number | undefined,
  truncationMode: TruncationMode,
): {
  displayValueText: string;
  displayRelativeValueText: string | undefined;
  actualValueWidth: number;
  fullValueText: string;
  fullRelativeValueText: string | undefined;
} => {
  return useMemo(() => {
    const relativeValueText = buildRelativeValueText(
      relativeValue,
      relativeValueUnit,
    );

    const valueUnitWithSpace = ` ${valueUnit}`;
    const fullValueText = `${value}${valueUnit ? valueUnitWithSpace : ''}`;

    if (!availableContainerWidth || availableContainerWidth <= 0) {
      const valueWidth = relativeValueText
        ? calculateTotalWidth400(fullValueText, relativeValueText)
        : calculateTotalWidth400(fullValueText);

      return {
        displayValueText: fullValueText,
        displayRelativeValueText: relativeValueText,
        actualValueWidth: valueWidth,
        fullValueText,
        fullRelativeValueText: relativeValueText,
      };
    }

    const maxValueContainerWidth =
      availableContainerWidth / 2 - GAP_BETWEEN_COLUMNS;

    if (!relativeValueText) {
      const truncatedValueText = getDisplayText(
        fullValueText,
        maxValueContainerWidth,
        truncationMode,
      );
      const actualValueWidth = calculateTotalWidth400(truncatedValueText);

      return {
        displayValueText: truncatedValueText,
        displayRelativeValueText: undefined,
        actualValueWidth,
        fullValueText,
        fullRelativeValueText: undefined,
      };
    }

    const relativeValueWidth = calculateTotalWidth400(relativeValueText);
    const valueWidth = calculateTotalWidth400(fullValueText);

    const totalValueContainerWidth = calculateTotalWidth400(
      relativeValueText,
      fullValueText,
      ' ',
    );

    if (totalValueContainerWidth <= maxValueContainerWidth) {
      return {
        displayValueText: fullValueText,
        displayRelativeValueText: relativeValueText,
        actualValueWidth: totalValueContainerWidth,
        fullValueText,
        fullRelativeValueText: relativeValueText,
      };
    }

    const maxRelativeValueWidth = Math.min(
      maxValueContainerWidth * 0.6,
      maxValueContainerWidth - SPACE_CHARACTER_WIDTH,
    );
    if (relativeValueWidth + SPACE_CHARACTER_WIDTH >= maxRelativeValueWidth) {
      const truncatedRelativeValue = getDisplayText(
        relativeValueText,
        maxRelativeValueWidth,
        truncationMode,
      );
      const actualRelativeValueWidth = calculateTotalWidth400(
        truncatedRelativeValue,
      );

      const remainingSpaceForValue =
        maxValueContainerWidth -
        actualRelativeValueWidth -
        SPACE_CHARACTER_WIDTH;
      const doesFitInAvailableSpace = valueWidth <= remainingSpaceForValue;
      const displayValueText = doesFitInAvailableSpace
        ? fullValueText
        : getDisplayText(fullValueText, remainingSpaceForValue, truncationMode);

      return {
        displayValueText,
        displayRelativeValueText: truncatedRelativeValue,
        actualValueWidth: calculateTotalWidth400(
          displayValueText,
          truncatedRelativeValue,
          ' ',
        ),
        fullValueText,
        fullRelativeValueText: relativeValueText,
      };
    } else {
      const actualRelativeValueWidth =
        calculateTotalWidth400(relativeValueText);
      const remainingSpaceForValue =
        maxValueContainerWidth -
        actualRelativeValueWidth -
        SPACE_CHARACTER_WIDTH;
      const doesFitInAvailableSpace = valueWidth <= remainingSpaceForValue;
      const displayValueText = doesFitInAvailableSpace
        ? fullValueText
        : getDisplayText(fullValueText, remainingSpaceForValue, truncationMode);

      return {
        displayValueText,
        displayRelativeValueText: relativeValueText,
        actualValueWidth: calculateTotalWidth400(
          displayValueText,
          relativeValueText,
          ' ',
        ),
        fullValueText,
        fullRelativeValueText: relativeValueText,
      };
    }
  }, [
    value,
    valueUnit,
    relativeValue,
    relativeValueUnit,
    availableContainerWidth,
    truncationMode,
  ]);
};
